/* ── Host ── */
:host {
  display: inline-block;
  overflow: visible;
}

/* ── Base ── */
.sq-tab {
  position: relative;
  display: flex;
  align-items: center;
  justify-content: center;
  overflow: visible;
  border: 1px solid var(--dcui-color-core-neutral-pale);
  border-bottom: 1px solid var(--dcui-color-core-neutral-pale);
  background: var(--dcui-color-core-neutral-offwhite);
  cursor: pointer;
  font-family: var(--dcui-font-family);
  box-sizing: border-box;
}

/* ── Sizes ── */
.sq-tab--l {
  flex-direction: column;
  gap: 12px;
  width: 120px;
  height: 112px;
  padding: 21px 20px;
}

.sq-tab--m {
  flex-direction: row;
  gap: 10px;
  width: 88px;
  height: 80px;
  padding: 12px 14px;
}

.sq-tab--s {
  flex-direction: row;
  gap: 10px;
  width: 60px;
  height: 56px;
  padding: 12px 14px;
}

/* ── Status: Active ── */
.sq-tab--active {
  background: var(--dcui-color-core-global-white);
  border-color: var(--dcui-color-core-global-white);
}

/* ── Status: Hover ── */
.sq-tab--hover {
  background: var(--dcui-color-core-global-white);
  border-color: var(--dcui-color-core-global-white);
}

/* ── Status: Disabled ── */
.sq-tab--disabled {
  background: var(--dcui-color-core-neutral-offwhite);
  border-color: var(--dcui-color-core-neutral-pale);
  cursor: not-allowed;
}

/* ── Icon ── */
.sq-tab__icon {
  position: relative;
  flex-shrink: 0;
  width: 29px;
  height: 29px;
}

.sq-tab__icon-mask {
  display: block;
  position: absolute;
  inset: 0;
  mask-size: 29px 29px;
  mask-repeat: no-repeat;
  mask-position: 0 0;
  -webkit-mask-size: 29px 29px;
  -webkit-mask-repeat: no-repeat;
  -webkit-mask-position: 0 0;
}

/* ── Label (L only) ── */
.sq-tab__label {
  font-size: var(--dcui-type-scale-s-size);
  font-weight: var(--dcui-font-weight-bold);
  line-height: 20px;
  text-align: center;
  width: 100%;
}

/* ── Tooltip (storybook-tooltip host) ── */
@keyframes tooltip-in-right {
  from { opacity: 0; transform: translateY(-50%) translateX(-6px); }
  to   { opacity: 1; transform: translateY(-50%) translateX(0); }
}

@keyframes tooltip-in-left {
  from { opacity: 0; transform: translateY(-50%) translateX(6px); }
  to   { opacity: 1; transform: translateY(-50%) translateX(0); }
}

.sq-tab__tooltip {
  position: absolute;
  top: 50%;
  z-index: 1000;
}

.sq-tab__tooltip--right {
  left: calc(100% + 8px);
  transform: translateY(-50%);
  animation: tooltip-in-right 0.18s ease-out forwards;
}

.sq-tab__tooltip--left {
  right: calc(100% + 8px);
  transform: translateY(-50%);
  animation: tooltip-in-left 0.18s ease-out forwards;
}

