/* ── Shell ── */
.tl {
  display: flex;
  flex-direction: column;
  align-items: flex-start;
  padding: 8px;
}

/* ── Bar area — hover target, relative anchor for tooltip ── */
.tl__bar-area {
  position: relative;
  /* top padding reserves space so the tooltip doesn't get clipped */
  padding-top: 96px;
  cursor: pointer;
}

/* ── Tooltip: absolutely positioned above indicator, animated ──
   Centred on indicator: left = indicator centre (147px sym / 67px asym),
   translateX(-50%) centres the 240px tooltip body over that point.
   Arrow (arrowSide=Bottom, left:50%) then points straight down to the dot. */
.tl__tooltip-wrap {
  position: absolute;
  /* sit just above the bar (arrow tip clears the bar top) */
  bottom: calc(100% - 96px + 4px);
  z-index: 100;
  pointer-events: none;

  /* hidden state */
  opacity: 0;
  transform: translateX(-50%) translateY(8px);
  transition: opacity 0.18s ease, transform 0.18s ease;
}

.tl--symmetric  .tl__tooltip-wrap { left: 147px; }
.tl--asymmetric .tl__tooltip-wrap { left:  67px; }

/* visible state */
.tl__tooltip-wrap--visible {
  opacity: 1;
  transform: translateX(-50%) translateY(0);
  pointer-events: auto;
}

/* ── Bar ── */
.tl__bar {
  display: flex;
  margin-top: 2px;
}

/* Figma: each segment 40 × 8 px */
.tl__seg {
  width: 40px;
  height: 8px;
  flex-shrink: 0;
}

.tl__seg--red    { background: var(--dcui-color-core-brand-light); }
.tl__seg--yellow { background: var(--dcui-color-core-alert-primary); }
.tl__seg--green  { background: var(--dcui-color-core-success-primary); }

/* ── Indicator circle ──
   Figma: ml-141px (sym) ml-61px (asym), mt-0, size 12×12px with extended visual.
   bar: mt-2px h-8px → centre at 6px from bar-area content top (after padding).
   circle 13px → top = 2 + 4 - 6.5 = -0.5px */
.tl__indicator {
  position: absolute;
  top: calc(96px - 0.5px); /* padding-top offset + bar vertical centre */
  transform: translateX(-50%);
}

.tl__indicator--sym  { left: 147px; }
.tl__indicator--asym { left:  67px; }

/* ── Labels ── */
.tl__labels {
  display: flex;
  margin-top: 2px;
}

.tl__label {
  height: 14px;
  width: 40px;
  flex-shrink: 0;
  font-size: var(--dcui-type-scale-xs-size);
  font-weight: var(--dcui-font-weight-regular);
  line-height: 16.67px;
  letter-spacing: 0.22px;
  color: var(--dcui-color-core-global-foreground);
  white-space: nowrap;
}

.tl__label--center { text-align: center; }
.tl__label--right  { text-align: right;  }

/* invisible spacers align labels to segment edges */
.tl__label--spacer {
  width: 20px;
  opacity: 0;
}

/* asymmetric: 2 labels centred within the 120px bar */
.tl--asymmetric .tl__labels {
  width: 120px;
  justify-content: center;
}

